def get_input():
    h, w = map(float, input().split())
    return h, w

def calc_bmi(h, w):
    return w / (h * h)

def classify(bmi):
    if bmi < 18.5:
        return "저체중"
    elif bmi < 23:
        return "정상"
    elif bmi < 25:
        return "과체중"
    else:
        return "비만"

h, w = get_input()
bmi = calc_bmi(h, w)
print(f"BMI: {bmi:.2f} ({classify(bmi)})")

def constant(n):
    return n * 2  # 연산 1번

def linear(n):
    total = 0
    for i in range(n):
        total += i
    return total

def quadratic(n):
    count = 0
    for i in range(n):
        for j in range(n):
            count += 1
    return count

for n in [10, 20, 40]:
    print(n, quadratic(n))
